// // This module implements a 64-bit down counter with enable and reset signals. The counter should decrement on every positive edge of the clock when the enable signal is high. If the reset signal is high, the counter should reset to zero. The counter should also output the current count value.
module counter_64bit (
    input wire clk,
    input wire reset,
    input wire enable,
    output reg [63:0] count
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 64'b0;
        end else if (enable) begin
            count <= count + 1;
        end
    end
endmodule
